public class CassandraSort extends Sort implements CassandraRel { public CassandraSort ( RelOptCluster cluster , RelTraitSet traitSet , RelNode child , RelCollation collation ) { super ( cluster , traitSet , child , collation , null , null ) ; assert getConvention ( ) == CassandraRel . CONVENTION ; assert getConvention ( ) == child . getConvention ( ) ; } @ Override public RelOptCost computeSelfCost ( RelOptPlanner planner , RelMetadataQuery mq ) { RelOptCost cost = super . computeSelfCost ( planner , mq ) ; if ( ! collation . getFieldCollations ( ) . isEmpty ( ) ) { return cost . multiplyBy ( 0.05 ) ; } else { return cost ; } } @ Override public Sort copy ( RelTraitSet traitSet , RelNode input , RelCollation newCollation , RexNode offset , RexNode fetch ) { return new CassandraSort ( getCluster ( ) , traitSet , input , collation ) ; } public void implement ( Implementor implementor ) { implementor . visitChild ( 0 , getInput ( ) ) ; List < RelFieldCollation > sortCollations = collation . getFieldCollations ( ) ; List < String > fieldOrder = new ArrayList < > ( ) ; if ( ! sortCollations . isEmpty ( ) ) { final List < RelDataTypeField > fields = getRowType ( ) . getFieldList ( ) ; for ( RelFieldCollation fieldCollation : sortCollations ) { final String name = fields . get ( fieldCollation . getFieldIndex ( ) ) . getName ( ) ; final String direction ; switch ( fieldCollation . getDirection ( ) ) { case DESCENDING : direction = "DESC" ; break ; default : direction = "ASC" ; } fieldOrder . add ( name + " " + direction ) ; } implementor . addOrder ( fieldOrder ) ; } } }